```javascript
function solve(s) {
    const VOWELS = new Set(['a', 'e', 'i', 'o', 'u']);

    /**
     * Checks if a character is a vowel.
     * @param {string} char 
     * @returns {boolean}
     */
    const isVowel = (char) => VOWELS.has(char);

    // Step 1: Gather Data (Counts and First Indices)
    const counts = new Map();
    const firstIndices = new Map();

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (isVowel(char)) {
            // Update count
            counts.set(char, (counts.get(char) || 0) + 1);

            // Record first index if not seen yet
            if (!firstIndices.has(char)) {
                firstIndices.set(char, i);
            }
        }
    }

    // Step 2: Determine Sorting Order

    // Convert Map entries to an array of objects for sorting
    const uniqueVowelsData = [];
    for (const char of counts.keys()) {
        uniqueVowelsData.push({
            char: char,
            freq: counts.get(char),
            firstIdx: firstIndices.get(char)
        });
    }

    // Sort based on criteria:
    // 1. Frequency (Non-increasing / Descending)
    // 2. First Appearance Index (Ascending)
    uniqueVowelsData.sort((a, b) => {
        // Primary sort: Frequency DESC
        if (b.freq !== a.freq) {
            return b.freq - a.freq;
        }
        // Secondary sort: First Index ASC
        return a.firstIdx - b.firstIdx;
    });

    // Construct the final sorted sequence of ALL vowels
    const sortedVowelSequence = [];
    for (const data of uniqueVowelsData) {
        const char = data.char;
        const freq = data.freq;
        for (let i = 0; i < freq; i++) {
            sortedVowelSequence.push(char);
        }
    }

    // Step 3: Reconstruct String
    let vowelPointer = 0;
    const resultChars = [];

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (isVowel(char)) {
            // Replace the vowel with the next vowel from the sorted sequence
            resultChars.push(sortedVowelSequence[vowelPointer]);
            vowelPointer++;
        } else {
            // Consonants remain unchanged
            resultChars.push(char);
        }
    }

    return resultChars.join('');
}
